INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('d6cf45c8-e4c5-5968-96eb-2de17dddbfa2', '5971ca22-2482-4b9e-bd40-f2283a214526', 'I have ___ money in my wallet.', '我的錢包裡有一點點錢。', 'a little', 'many', 'few', 'several', 'a (一個) + little (小的) → 用於不可數名詞前，表示「一些、一點點」。', 'a (一個) + little (小) → 聯想成「一個小小的量」→ 一點點。', '2026-07-06 12:14:18', '2026-07-06 12:14:18'),
('bd9f06f6-14c6-557f-89c4-3a95c8a87516', '3479dd3b-ac1b-40ec-bc0b-afef17583b82', 'It took him several months to ___ to the cold weather in Northern Europe.', '他在北歐生活時，花了幾個月的時間才適應那裡的寒冷天氣。', 'adjust', 'belong', 'oppose', 'react', 'ad- (朝向) + just (正確/公正) → 使之趨向正確或合適 → 調整、適應。', 'ad (趨向) + just (正義/公平) → 朝著正確的方向去修正 → 調整、適應。', '2026-07-06 17:45:56', '2026-07-06 17:45:56'),
('4542218e-3e58-51c7-a7ea-1a0dfba9d5ae', 'f4f1dda7-4095-46d7-b460-16e492f8e109', 'The doctor decided to ___ her patient to undergo surgery to avoid further complications.', '醫生決定建議她的病人接受手術，以避免進一步的併發症。', 'advise', 'forbid', 'allow', 'force', '字根 ad- (向著) + vis (看) → 向某人指點方向 → 建議、勸告。', '想像你在向 (ad) 某人展示 (vis) 正確的路徑，就是在給予建議。', '2026-07-06 18:15:53', '2026-07-06 18:15:53'),
('739388b7-3195-530f-b963-6aba75190ce6', '59b2e7a4-aa29-4156-9544-de3615378111', 'He prefers to travel ___ so that he can follow his own schedule.', '他更喜歡獨自旅行，這樣他就可以按照自己的行程安排。', 'alone', 'quickly', 'happily', 'slowly', 'a- (處於...狀態) + lone (單獨的)', 'a (處於) + lone (單獨) → 獨自地。', '2026-07-06 20:10:50', '2026-07-06 20:10:50'),
('15a743dd-2c86-5678-936a-e0345db8b56e', '0a11c3ba-9554-43a8-8243-fc7d20c865cb', 'We visited an ___ temple during our trip to Greece.', '我們在希臘旅行期間參觀了一座古代的寺廟。', 'ancient', 'modern', 'expensive', 'famous', 'anc- 源自拉丁語 antiquus，表示古老的、早期的。', '看到 ancient 就聯想到 ancient history (古代史)，那是關於很久很久以前的事情。', '2026-07-06 14:06:57', '2026-07-06 14:06:57'),
('0e8661d0-f10f-539c-a272-6b03b0ad4352', 'f5257995-6630-4b2f-a32d-a93e55bc92eb', 'To improve your vocabulary, you should try to find an ___ for every new word you learn to help you remember its opposite.', '為了增進詞彙量，你應該嘗試為你學過的每個新單字找一個反義字，以幫助你記住它的相反意思。', 'antonym', 'synonym', 'definition', 'example', 'anti- (相反的) + -onym (名稱/字)', 'anti- (相反) + -onym (名稱) → 反義字', '2026-07-06 21:57:22', '2026-07-06 21:57:22'),
('2a9c2c63-670e-52e7-a052-242fa43d3602', '7f8fecc5-3f19-43b2-8f66-492087095cf1', 'We ___ hungry, so we do not want to eat.', '我們不餓，所以我們不想吃東西。', 'aren''t', 'don''t', 'won''t', 'can''t', 'are 與 not 的縮寫形式。', '複數主詞 (We, You, They) + aren''t → 表示「不是」。', '2026-07-06 14:44:12', '2026-07-06 14:44:12'),
('367149d8-6a9c-510b-a88e-4caaa9c1cb7e', 'e55be9e4-4e7e-4b68-9e36-943fe6faadbf', 'The museum displayed a collection of ___ flowers that looked incredibly real, even from a distance.', '博物館展示了一系列看起來非常逼真的假花（人工花），即使從遠處看也是如此。', 'artificial', 'natural', 'beautiful', 'ancient', 'art (技巧/藝術) + -ficial (形容詞字尾) → 指用技巧或手段製造出來的 → 人工的。', '想像藝術家 (artist) 用技巧 (art) 做出看起來像真的東西 → artificial (人工的)。', '2026-07-07 00:28:40', '2026-07-07 00:28:40'),
('8bd4af2f-d604-545f-af7d-6e2dec4f552a', 'f1525e06-e382-4bfa-9f43-2fbaf293b488', 'We go down the stairs to the ___ to find the washing machine.', '我們走下樓梯去___找洗衣機。', 'basement', 'attic', 'kitchen', 'balcony', 'base (基礎) + ment (名詞字尾) → 地下室', 'base 是基礎的意思，加上 ment 變成名詞，想像房子最底層的基礎部分就是地下室。', '2026-07-07 02:30:00', '2026-07-07 02:30:00'),
('1cc7aedc-56df-5215-9b48-a19f3e2638a6', '26be81ce-d332-4409-85fb-073f9854900e', 'The little cat is hiding ___ the big box.', '那隻小貓躲在大箱子後面。', 'behind', 'under', 'beside', 'near', 'hind (後面的) → 表示位置在後方', '想像你的背 (back) 在身體的後方，behind 就是在後面。', '2026-07-07 03:17:27', '2026-07-07 03:17:27'),
('c44d5458-28c9-523f-9851-1ac753f1833a', '21c1ad12-f839-492b-a8e3-8bb8d03cef06', 'He exercises every day to have a healthy ___.', '他每天運動以擁有健康的身體。', 'body', 'voice', 'name', 'dream', '名詞，指人的身體或軀幹。', 'Body → 像波地 → 波地很強壯。', '2026-07-07 04:56:24', '2026-07-07 04:56:24'),
('82ea869f-b36b-5f4f-884b-2ba60ee0a372', '91450cde-863a-4e5c-9729-45f6095c8016', 'Please ___ the bottle before you leave.', '離開之前請把瓶蓋蓋好。', 'cap', 'wash', 'open', 'hold', 'cap 當動詞使用時，表示「蓋上」或「封住」的動作。', 'cap 想像成瓶蓋 (cap) 蓋在瓶口上的動作。', '2026-07-07 02:21:54', '2026-07-07 02:21:54'),
('50c1a32d-76b5-5bd4-976f-5798a3aeeb42', 'dea312c4-c14e-4d07-8e20-f5081a9a366e', 'The sky is very ___ today, so we cannot see the stars at night.', '今天天空非常多雲，所以我們晚上看不到星星。', 'cloudy', 'bright', 'clear', 'blue', 'cloud (雲) + y (形容詞字尾) → 多雲的', '記住 cloud 是雲，加上 y 就變成形容詞「多雲的」。', '2026-07-07 04:49:51', '2026-07-07 04:49:51'),
('436a7c77-0a49-53d9-9270-650d7632a576', 'be9deee2-6b5b-45bf-9891-190ff85e4c7c', 'The students want to ___ the new rules together.', '學生們想一起討論這些新規則。', 'discuss', 'forget', 'enjoy', 'borrow', 'dis- (強調) + cuss (敲擊) → 透過交談來交換意見，即「討論」。', '想像大家把想法敲出來交換，就是 discuss。', '2026-07-07 04:46:44', '2026-07-07 04:46:44'),
('c82e2d06-3361-5305-99ba-e209aaf8cae6', '814d7410-69b9-4ed3-a3a5-5c5611b43e6e', 'She has a lot of work ___ in teaching English.', '她在教英文方面有很多工作經驗。', 'experience', 'homework', 'music', 'lunch', 'ex (向外) + peri (嘗試) → 向外嘗試事物', '透過向外的嘗試與實作，獲得「經驗」。', '2026-07-07 05:24:08', '2026-07-07 05:24:08'),
('04c95bdc-796e-50f6-a4c2-c10c3f409c76', 'f64aab4c-6665-4617-a07e-5f6b210dc975', 'I am sorry, I did not quite ___ what you just said.', '很抱歉，我不太明白你剛才說了什麼。', 'get', 'tell', 'feel', 'want', 'get 在口語中有「理解」或「明白」的意思。', 'I get it! → 我懂了！', '2026-07-05 07:56:07', '2026-07-05 07:56:07'),
('7b7184d7-f21c-5598-85de-cdf91258219a', '8e57d228-2375-4684-9b15-7e73584141b6', 'She ___ many books from the library yesterday.', '她昨天從圖書館借了一些書。', 'got', 'made', 'took', 'danced', '表示「得到」或「拿到」的意思。', 'Get it! (拿到它)', '2026-07-05 07:16:15', '2026-07-05 07:16:15'),
('05bcc527-2b1b-56b4-ab84-eab6b414658e', 'c8f5ae6e-0be6-420b-a927-4ab8a3519a32', 'If ___ are to succeed in this competitive industry, innovation must be our top priority.', '如果我們要在這個競爭激烈的行業中取得成功，創新必須是我們的首要任務。', 'we', 'they', 'he', 'she', '第一人稱複數代名詞，用於主詞位置，與複數動詞搭配。', 'we 代表「我們」，是一個包含說話者在內的集體。', '2026-07-06 11:04:30', '2026-07-06 11:04:30'),
('8766a75a-cc7b-5a8f-bdb5-b8e5331b12d6', '74449081-948e-4337-b24b-e50b8a25cddf', '___ color is your backpack?', '你的書包是什麼顏色的？', 'what', 'which', 'some', 'many', '這是一個疑問形容詞，用來修飾後面的名詞。', '看到問句想問『什麼』，就找 what！', '2026-07-05 11:57:46', '2026-07-05 11:57:46'),
('9789b269-55c1-598b-8c5e-4b2562c68d52', '4cb49395-91b8-403d-bb41-77e22ac4ae2f', 'She has a strong ___ to win the game.', '她有強烈的意志要贏得比賽。', 'will', 'dream', 'hope', 'wish', 'will 為單字，無詞根或詞綴。', 'will → 內心的強大意志。', '2026-07-05 13:36:55', '2026-07-05 13:36:55');
